import React, { useState, useEffect } from 'react';

export default function StatusTracker({ appTheme }) {
    const isDark = appTheme === 'dark';

    // Palet warna agar selaras dengan tema aplikasi
    const colors = {
        cardBg: '#171717',
        border: '#262626',
        textMain: '#ffffff',
        textMuted: '#a3a3a3',
        accent: '#f59e0b'
    };

    const [applications] = useState([
        { id_lamaran: 'APP-001', title: 'Fullstack Developer', company: 'PasukanYerusSolo', applied_date: '2026-05-28', status: 'Diproses', pesan_hrd: 'Berkas CV Anda sedang ditinjau.' },
        { id_lamaran: 'APP-002', title: 'React Frontend Engineer', company: 'TechEase Indonesia', applied_date: '2026-05-15', status: 'Diterima', pesan_hrd: 'Selamat! Anda diundang interview.' }
    ]);

    const getStatusStyle = (status) => {
        if (status === 'Diterima') return { bg: '#064e3b', text: '#34d399' };
        if (status === 'Ditolak') return { bg: '#7f1d1d', text: '#f87171' };
        return { bg: '#78350f', text: '#fbbf24' }; // Diproses
    };

    return (
        <div style={{ padding: '24px', height: '100%', overflowY: 'auto', color: colors.textMain }}>
            <h2 style={{ marginBottom: '24px' }}>Status Lamaran Saya</h2>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {applications.map((app) => {
                    const badge = getStatusStyle(app.status);
                    return (
                        <div key={app.id_lamaran} style={{ 
                            background: colors.cardBg, 
                            border: `1px solid ${colors.border}`, 
                            borderRadius: '12px', 
                            padding: '20px',
                            display: 'grid',
                            gridTemplateColumns: '1fr auto', // Layout kolom proporsional
                            alignItems: 'center',
                            gap: '20px'
                        }}>
                            <div>
                                <h3 style={{ margin: '0 0 4px 0' }}>{app.title}</h3>
                                <p style={{ margin: '0 0 8px 0', color: colors.accent, fontWeight: '600' }}>{app.company}</p>
                                <p style={{ margin: '0', fontSize: '13px', color: colors.textMuted }}>
                                    📅 Dilamar pada: {app.applied_date}
                                </p>
                                {app.pesan_hrd && (
                                    <div style={{ marginTop: '12px', fontSize: '13px', fontStyle: 'italic', color: colors.textMuted }}>
                                        💬 "{app.pesan_hrd}"
                                    </div>
                                )}
                            </div>

                            <div style={{ 
                                background: badge.bg, 
                                color: badge.text, 
                                padding: '8px 16px', 
                                borderRadius: '20px', 
                                fontWeight: '700', 
                                fontSize: '12px' 
                            }}>
                                {app.status}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}
